function fetchViaProxy\(targetHost, targetPath\) {
  return new Promise\(\(resolve, reject\) => {
    const req = http.request\({
      host: proxyUrl.hostname,
      port: proxyUrl.port,
      method: \\"CONNECT\\",
      path: targetHost + \\":443\\",
      headers: {
        \\"Proxy-Authorization\\": \\"Basic \\" + Buffer.from\(proxyUrl.username + \\":\\" + proxyUrl.password\).toString\(\\"base64\\"\),
      },
      timeout: 15000,
    }\);

    req.on\(\\"connect\\", \(res, socket\) => {
      if \(res.statusCode !== 200\) { reject\(new Error\(\\"CONNECT \\" + res.statusCode\)\); return; }
      const tlsSocket = tls.connect\({ socket, servername: targetHost }, \(\) => {
        tlsSocket.write\(\\"GET \\" + targetPath + \\" HTTP/1.1\\\\r\\\\nHost: \\" + targetHost + \\"\\\\r\\\\nUser-Agent: Mozilla/5.0 \(Windows NT 10.0; Win64; x64\) AppleWebKit/537.36\\\\r\\\\nConnection: close\\\\r\\\\n\\\\r\\\\n\\"\);
