    }\);

    req.on\(\\"connect\\", \(res, socket\) => {
      if \(res.statusCode !== 200\) { reject\(new Error\(\\"CONNECT \\" + res.statusCode\)\); return; }

      const httpsReq = https.request\({
        hostname: target.hostname,
        path: target.pathname,
        method: \\"GET\\",
        socket: socket,
        agent: false,
        headers: {
          \\"Host\\": target.hostname,
